"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[5727],{46808(n,r,e){e.r(r),e.d(r,{assets:()=>i,contentTitle:()=>c,default:()=>l,frontMatter:()=>a,metadata:()=>t,toc:()=>d});const t=JSON.parse('{"id":"cpp20/coroutines-basics","title":"\u534f\u7a0b\u57fa\u7840 (Coroutines: co_await, co_yield, co_return)","description":"C++20 \u534f\u7a0b\u57fa\u7840 (Coroutines: co_await, co_yield, co_return) \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp20/30-coroutines-basics.md","sourceDirName":"cpp20","slug":"/cpp20/30-coroutines-basics","permalink":"/LearnModernCpp/docs/cpp20/30-coroutines-basics","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp20","permalink":"/LearnModernCpp/docs/tags/cpp-20"},{"inline":true,"label":"coroutines_basics","permalink":"/LearnModernCpp/docs/tags/coroutines-basics"}],"version":"current","sidebarPosition":31,"frontMatter":{"sidebar_position":31,"slug":"30-coroutines-basics","title":"\u534f\u7a0b\u57fa\u7840 (Coroutines: co_await, co_yield, co_return)","description":"C++20 \u534f\u7a0b\u57fa\u7840 (Coroutines: co_await, co_yield, co_return) \u6559\u5b66\u793a\u4f8b","tags":["cpp20","coroutines_basics"]},"sidebar":"docs","previous":{"title":"\u81ea\u5b9a\u4e49\u8303\u56f4\u548c\u89c6\u56fe\u9002\u914d\u5668 (Custom Ranges and View Adaptors)","permalink":"/LearnModernCpp/docs/cpp20/22-ranges-custom"},"next":{"title":"Generator \u7c7b\u578b (co_yield \u751f\u6210\u5668)","permalink":"/LearnModernCpp/docs/cpp20/31-coroutines-generator"}}');var s=e(74848),o=e(28453);const a={sidebar_position:31,slug:"30-coroutines-basics",title:"\u534f\u7a0b\u57fa\u7840 (Coroutines: co_await, co_yield, co_return)",description:"C++20 \u534f\u7a0b\u57fa\u7840 (Coroutines: co_await, co_yield, co_return) \u6559\u5b66\u793a\u4f8b",tags:["cpp20","coroutines_basics"]},c="\u534f\u7a0b\u57fa\u7840 (Coroutines: co_await, co_yield, co_return)",i={},d=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function u(n){const r={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,o.R)(),...n.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(r.header,{children:(0,s.jsx)(r.h1,{id:"\u534f\u7a0b\u57fa\u7840-coroutines-co_await-co_yield-co_return",children:"\u534f\u7a0b\u57fa\u7840 (Coroutines: co_await, co_yield, co_return)"})}),"\n",(0,s.jsx)(r.p,{children:"C++20 \u6807\u51c6\u5f15\u5165\u7684 \u534f\u7a0b\u57fa\u7840 (Coroutines: co_await, co_yield, co_return) \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,s.jsx)(r.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,s.jsx)(r.pre,{children:(0,s.jsx)(r.code,{className:"language-cpp",metastring:'title="cpp20/30_coroutines_basics.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: \u534f\u7a0b\u57fa\u7840 (Coroutines: co_await, co_yield, co_return)\r\n * \u6240\u5c5e\u6807\u51c6: C++20\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: \u534f\u7a0b\u662f\u4e00\u79cd\u53ef\u4ee5\u6682\u505c\u548c\u6062\u590d\u6267\u884c\u7684\u51fd\u6570\u3002\r\n *          C++20 \u5f15\u5165\u4e86 co_await\u3001co_yield\u3001co_return \u4e09\u4e2a\u5173\u952e\u5b57\uff0c\r\n *          \u4ee5\u53ca\u5e95\u5c42\u7684 promise_type \u548c coroutine_handle \u673a\u5236\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: \u5f02\u6b65\u7f16\u7a0b\u3001\u751f\u6210\u5668\u3001\u72b6\u6001\u673a\u7b49\u573a\u666f\u9700\u8981\u51fd\u6570\u80fd\u591f\r\n *             \u6682\u505c\u6267\u884c\u5e76\u5728\u4e4b\u540e\u6062\u590d\u3002\u4f20\u7edf\u7684\u56de\u8c03\u548c\u72b6\u6001\u673a\u4ee3\u7801\u590d\u6742\uff0c\r\n *             \u534f\u7a0b\u63d0\u4f9b\u4e86\u66f4\u76f4\u89c2\u7684\u5199\u6cd5\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - co_await: \u6682\u505c\u534f\u7a0b\uff0c\u7b49\u5f85\u5f02\u6b65\u64cd\u4f5c\u5b8c\u6210\r\n *   - co_yield: \u4ea7\u51fa\u4e00\u4e2a\u503c\u5e76\u6682\u505c\r\n *   - co_return: \u8fd4\u56de\u6700\u7ec8\u7ed3\u679c\u5e76\u7ed3\u675f\u534f\u7a0b\r\n *   - promise_type: \u63a7\u5236\u534f\u7a0b\u884c\u4e3a\u7684\u7c7b\u578b\r\n *   - coroutine_handle: \u7528\u4e8e\u6062\u590d\u548c\u9500\u6bc1\u534f\u7a0b\u7684\u53e5\u67c4\r\n * ============================================================\r\n */\r\n\r\n#include <coroutine>\r\n#include <iostream>\r\n#include <optional>\r\n#include <string>\r\n#include <utility>\r\n\r\n// ===================== basic_usage() =====================\r\n\r\n// \u6700\u7b80\u5355\u7684 Task \u7c7b\u578b\uff1a\u652f\u6301 co_return\r\ntemplate<typename T>\r\nclass Task {\r\npublic:\r\n    // promise_type \u662f\u534f\u7a0b\u7684\u6838\u5fc3\uff1a\u63a7\u5236\u534f\u7a0b\u7684\u521b\u5efa\u3001\u6682\u505c\u3001\u6062\u590d\u548c\u9500\u6bc1\r\n    struct promise_type {\r\n        std::optional<T> result;\r\n\r\n        // \u521b\u5efa Task \u5bf9\u8c61\uff08\u534f\u7a0b\u7684\u8fd4\u56de\u503c\uff09\r\n        Task get_return_object() {\r\n            return Task{std::coroutine_handle<promise_type>::from_promise(*this)};\r\n        }\r\n\r\n        // \u534f\u7a0b\u5f00\u59cb\u65f6\u7684\u884c\u4e3a\uff1asuspend_never = \u7acb\u5373\u5f00\u59cb\u6267\u884c\r\n        std::suspend_always initial_suspend() noexcept { return {}; }\r\n\r\n        // \u534f\u7a0b\u7ed3\u675f\u65f6\u7684\u884c\u4e3a\uff1asuspend_always = \u6682\u505c\u7b49\u5f85\u9500\u6bc1\r\n        std::suspend_always final_suspend() noexcept { return {}; }\r\n\r\n        // co_return \u7684\u5904\u7406\r\n        void return_value(T value) {\r\n            result = std::move(value);\r\n        }\r\n\r\n        // \u672a\u6355\u83b7\u5f02\u5e38\u7684\u5904\u7406\r\n        void unhandled_exception() {\r\n            std::terminate();\r\n        }\r\n    };\r\n\r\n    // \u6784\u9020\u548c\u6790\u6784\r\n    explicit Task(std::coroutine_handle<promise_type> h) : handle_(h) {}\r\n    ~Task() {\r\n        if (handle_) handle_.destroy();\r\n    }\r\n\r\n    // \u7981\u6b62\u590d\u5236\r\n    Task(const Task&) = delete;\r\n    Task& operator=(const Task&) = delete;\r\n\r\n    // \u5141\u8bb8\u79fb\u52a8\r\n    Task(Task&& other) noexcept : handle_(std::exchange(other.handle_, nullptr)) {}\r\n    Task& operator=(Task&& other) noexcept {\r\n        if (this != &other) {\r\n            if (handle_) handle_.destroy();\r\n            handle_ = std::exchange(other.handle_, nullptr);\r\n        }\r\n        return *this;\r\n    }\r\n\r\n    // \u6062\u590d\u534f\u7a0b\u6267\u884c\r\n    void resume() {\r\n        if (handle_ && !handle_.done()) {\r\n            handle_.resume();\r\n        }\r\n    }\r\n\r\n    // \u83b7\u53d6\u7ed3\u679c\r\n    T result() const {\r\n        return handle_.promise().result.value();\r\n    }\r\n\r\n    // \u534f\u7a0b\u662f\u5426\u5b8c\u6210\r\n    bool done() const {\r\n        return handle_.done();\r\n    }\r\n\r\nprivate:\r\n    std::coroutine_handle<promise_type> handle_;\r\n};\r\n\r\n// \u4f7f\u7528 co_return \u7684\u7b80\u5355\u534f\u7a0b\r\nTask<int> compute_value(int x, int y) {\r\n    std::cout << "  [\u534f\u7a0b] \u5f00\u59cb\u8ba1\u7b97 " << x << " + " << y << "\\n";\r\n    co_return x + y;\r\n}\r\n\r\nTask<std::string> greet(const std::string& name) {\r\n    std::cout << "  [\u534f\u7a0b] \u751f\u6210\u95ee\u5019\u8bed...\\n";\r\n    co_return "\u4f60\u597d, " + name + "!";\r\n}\r\n\r\nvoid basic_usage() {\r\n    std::cout << "--- \u57fa\u7840\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // \u521b\u5efa\u534f\u7a0b\uff08initial_suspend = suspend_always\uff0c\u6240\u4ee5\u4e0d\u4f1a\u7acb\u5373\u6267\u884c\uff09\r\n    std::cout << "\u521b\u5efa\u534f\u7a0b...\\n";\r\n    auto task = compute_value(3, 5);\r\n\r\n    std::cout << "\u534f\u7a0b\u5df2\u521b\u5efa\u4f46\u672a\u6267\u884c\\n";\r\n    std::cout << "\u6062\u590d\u6267\u884c...\\n";\r\n    task.resume();  // \u6267\u884c\u5230 co_return\r\n\r\n    std::cout << "\u7ed3\u679c: " << task.result() << "\\n";\r\n\r\n    // \u5b57\u7b26\u4e32\u534f\u7a0b\r\n    std::cout << "\\n\u521b\u5efa\u5b57\u7b26\u4e32\u534f\u7a0b...\\n";\r\n    auto greeting = greet("C++20");\r\n    greeting.resume();\r\n    std::cout << "\u95ee\u5019: " << greeting.result() << "\\n";\r\n}\r\n\r\n// ===================== advanced_usage() =====================\r\n\r\n// \u652f\u6301\u6682\u505c/\u6062\u590d\u591a\u6b21\u7684\u534f\u7a0b\uff08\u4f7f\u7528 co_await\uff09\r\nclass Resumable {\r\npublic:\r\n    struct promise_type {\r\n        Resumable get_return_object() {\r\n            return Resumable{std::coroutine_handle<promise_type>::from_promise(*this)};\r\n        }\r\n        std::suspend_always initial_suspend() noexcept { return {}; }\r\n        std::suspend_always final_suspend() noexcept { return {}; }\r\n        void return_void() {}\r\n        void unhandled_exception() { std::terminate(); }\r\n    };\r\n\r\n    explicit Resumable(std::coroutine_handle<promise_type> h) : handle_(h) {}\r\n    ~Resumable() { if (handle_) handle_.destroy(); }\r\n\r\n    Resumable(const Resumable&) = delete;\r\n    Resumable& operator=(const Resumable&) = delete;\r\n    Resumable(Resumable&& other) noexcept : handle_(std::exchange(other.handle_, nullptr)) {}\r\n\r\n    void resume() {\r\n        if (handle_ && !handle_.done()) {\r\n            handle_.resume();\r\n        }\r\n    }\r\n\r\n    bool done() const { return handle_.done(); }\r\n\r\nprivate:\r\n    std::coroutine_handle<promise_type> handle_;\r\n};\r\n\r\n// \u591a\u6b21\u6682\u505c\u7684\u534f\u7a0b\r\nResumable multi_step_task() {\r\n    std::cout << "  [\u6b65\u9aa4 1] \u521d\u59cb\u5316...\\n";\r\n    co_await std::suspend_always{};  // \u6682\u505c\r\n\r\n    std::cout << "  [\u6b65\u9aa4 2] \u5904\u7406\u6570\u636e...\\n";\r\n    co_await std::suspend_always{};  // \u518d\u6b21\u6682\u505c\r\n\r\n    std::cout << "  [\u6b65\u9aa4 3] \u6e05\u7406...\\n";\r\n    co_await std::suspend_always{};  // \u518d\u6b21\u6682\u505c\r\n\r\n    std::cout << "  [\u6b65\u9aa4 4] \u5b8c\u6210!\\n";\r\n    // co_return; (\u9690\u5f0f)\r\n}\r\n\r\n// \u81ea\u5b9a\u4e49 Awaitable \u7c7b\u578b\r\nstruct TimedSuspend {\r\n    int id;\r\n\r\n    // Awaitable \u4e09\u4ef6\u5957\r\n    bool await_ready() const noexcept {\r\n        std::cout << "    await_ready(" << id << "): \u68c0\u67e5\u662f\u5426\u9700\u8981\u6682\u505c\\n";\r\n        return false;  // false = \u9700\u8981\u6682\u505c\r\n    }\r\n\r\n    void await_suspend(std::coroutine_handle<>) const noexcept {\r\n        std::cout << "    await_suspend(" << id << "): \u534f\u7a0b\u5df2\u6682\u505c\\n";\r\n    }\r\n\r\n    int await_resume() const noexcept {\r\n        std::cout << "    await_resume(" << id << "): \u534f\u7a0b\u6062\u590d\uff0c\u8fd4\u56de " << id * 10 << "\\n";\r\n        return id * 10;  // co_await \u8868\u8fbe\u5f0f\u7684\u7ed3\u679c\r\n    }\r\n};\r\n\r\n// \u652f\u6301 co_await \u8fd4\u56de\u503c\u7684 Task\r\nResumable awaitable_demo() {\r\n    std::cout << "  \u5f00\u59cb awaitable \u6f14\u793a\\n";\r\n\r\n    // co_await \u7684\u8fc7\u7a0b\uff1a\r\n    // 1. \u8c03\u7528 await_ready() \u2192 \u5982\u679c true\uff0c\u4e0d\u6682\u505c\r\n    // 2. \u5982\u679c false\uff0c\u8c03\u7528 await_suspend() \u2192 \u6682\u505c\u534f\u7a0b\r\n    // 3. \u6062\u590d\u65f6\u8c03\u7528 await_resume() \u2192 \u8fd4\u56de\u7ed3\u679c\r\n    co_await TimedSuspend{1};\r\n\r\n    std::cout << "  \u7b2c\u4e00\u6b21\u6062\u590d\u540e\\n";\r\n    co_await TimedSuspend{2};\r\n\r\n    std::cout << "  \u7b2c\u4e8c\u6b21\u6062\u590d\u540e\uff0c\u5b8c\u6210!\\n";\r\n}\r\n\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- \u9ad8\u7ea7\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // \u591a\u6b65\u9aa4\u534f\u7a0b\r\n    std::cout << "-- \u591a\u6b65\u9aa4\u534f\u7a0b (co_await suspend_always) --\\n";\r\n    auto task = multi_step_task();\r\n\r\n    int step = 0;\r\n    while (!task.done()) {\r\n        std::cout << "[\u8c03\u7528\u8005] \u6062\u590d\u7b2c " << ++step << " \u6b65\\n";\r\n        task.resume();\r\n    }\r\n\r\n    // \u81ea\u5b9a\u4e49 Awaitable\r\n    std::cout << "\\n-- \u81ea\u5b9a\u4e49 Awaitable --\\n";\r\n    auto demo = awaitable_demo();\r\n\r\n    std::cout << "[\u8c03\u7528\u8005] \u7b2c1\u6b21\u6062\u590d\\n";\r\n    demo.resume();\r\n\r\n    std::cout << "[\u8c03\u7528\u8005] \u7b2c2\u6b21\u6062\u590d\\n";\r\n    demo.resume();\r\n\r\n    std::cout << "[\u8c03\u7528\u8005] \u7b2c3\u6b21\u6062\u590d\\n";\r\n    demo.resume();\r\n\r\n    // \u534f\u7a0b\u53e5\u67c4\u7684\u751f\u547d\u5468\u671f\r\n    std::cout << "\\n-- \u534f\u7a0b\u7684\u751f\u547d\u5468\u671f --\\n";\r\n    std::cout << "1. \u8c03\u7528\u534f\u7a0b\u51fd\u6570 \u2192 \u521b\u5efa\u534f\u7a0b\u5e27(\u5806\u5206\u914d)\\n";\r\n    std::cout << "2. initial_suspend \u2192 \u51b3\u5b9a\u662f\u5426\u7acb\u5373\u6267\u884c\\n";\r\n    std::cout << "3. \u6267\u884c\u534f\u7a0b\u4f53 \u2192 \u9047\u5230 co_await/co_yield \u6682\u505c\\n";\r\n    std::cout << "4. resume() \u2192 \u4ece\u6682\u505c\u70b9\u6062\u590d\u6267\u884c\\n";\r\n    std::cout << "5. co_return \u6216\u51fd\u6570\u7ed3\u675f \u2192 final_suspend\\n";\r\n    std::cout << "6. destroy() \u2192 \u9500\u6bc1\u534f\u7a0b\u5e27\\n";\r\n}\r\n\r\n// ===================== pitfalls() =====================\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- \u6613\u9519\u70b9 ---\\n\\n";\r\n\r\n    // \u9677\u96311\uff1a\u534f\u7a0b\u5e27\u7684\u5185\u5b58\u7ba1\u7406\r\n    std::cout << "1. \u534f\u7a0b\u5e27\u5728\u5806\u4e0a\u5206\u914d\uff0c\u5fc5\u987b\u6b63\u786e\u9500\u6bc1:\\n";\r\n    std::cout << "   handle.destroy() \u9500\u6bc1\u534f\u7a0b\u5e27\\n";\r\n    std::cout << "   \u901a\u5e38\u5728 Task \u7684\u6790\u6784\u51fd\u6570\u4e2d\u8c03\u7528\\n";\r\n    std::cout << "   \u53cc\u91cd\u9500\u6bc1 = \u672a\u5b9a\u4e49\u884c\u4e3a!\\n\\n";\r\n\r\n    // \u9677\u96312\uff1a\u60ac\u5782\u5f15\u7528\r\n    std::cout << "2. \u534f\u7a0b\u4e2d\u7684\u5f15\u7528\u53c2\u6570\u53ef\u80fd\u60ac\u5782:\\n";\r\n    std::cout << "   Task foo(const string& s) {  // s \u53ef\u80fd\u5728\u6682\u505c\u540e\u5931\u6548!\\n";\r\n    std::cout << "       co_await something;\\n";\r\n    std::cout << "       cout << s;  // \u5982\u679c\u8c03\u7528\u8005\u5df2\u9500\u6bc1 s \u2192 \u672a\u5b9a\u4e49\u884c\u4e3a\\n";\r\n    std::cout << "   }\\n";\r\n    std::cout << "   \u89e3\u51b3\uff1a\u6309\u503c\u4f20\u9012\u53c2\u6570\\n\\n";\r\n\r\n    // \u9677\u96313\uff1apromise_type \u5fc5\u987b\u5305\u542b\u7279\u5b9a\u6210\u5458\r\n    std::cout << "3. promise_type \u5fc5\u987b\u5305\u542b\u4ee5\u4e0b\u6210\u5458:\\n";\r\n    std::cout << "   - get_return_object()     \u2192 \u521b\u5efa\u8fd4\u56de\u5bf9\u8c61\\n";\r\n    std::cout << "   - initial_suspend()       \u2192 \u521d\u59cb\u6682\u505c\u7b56\u7565\\n";\r\n    std::cout << "   - final_suspend()         \u2192 \u6700\u7ec8\u6682\u505c\u7b56\u7565\\n";\r\n    std::cout << "   - unhandled_exception()   \u2192 \u5f02\u5e38\u5904\u7406\\n";\r\n    std::cout << "   - return_void() \u6216 return_value()  \u2192 co_return \u5904\u7406\\n\\n";\r\n\r\n    // \u9677\u96314\uff1afinal_suspend \u901a\u5e38\u5e94\u8be5\u8fd4\u56de suspend_always\r\n    std::cout << "4. final_suspend() \u901a\u5e38\u8fd4\u56de suspend_always:\\n";\r\n    std::cout << "   \u5982\u679c\u8fd4\u56de suspend_never\uff0c\u534f\u7a0b\u5e27\u5728\u7ed3\u675f\u65f6\u81ea\u52a8\u9500\u6bc1\\n";\r\n    std::cout << "   \u8fd9\u65f6 handle.destroy() \u5c31\u4e0d\u5e94\u8be5\u518d\u8c03\u7528\\n";\r\n    std::cout << "   \u800c\u4e14\u7ed3\u679c\u53ef\u80fd\u8fd8\u6ca1\u88ab\u8bfb\u53d6\u5c31\u9500\u6bc1\u4e86\\n\\n";\r\n\r\n    // \u9677\u96315\uff1a\u4e0d\u80fd\u5728\u6784\u9020\u51fd\u6570/\u6790\u6784\u51fd\u6570\u4e2d\u4f7f\u7528 co_await\r\n    std::cout << "5. \u9650\u5236:\\n";\r\n    std::cout << "   - \u6784\u9020\u51fd\u6570\u548c\u6790\u6784\u51fd\u6570\u4e0d\u80fd\u662f\u534f\u7a0b\\n";\r\n    std::cout << "   - main \u51fd\u6570\u4e0d\u80fd\u662f\u534f\u7a0b\\n";\r\n    std::cout << "   - constexpr \u51fd\u6570\u4e0d\u80fd\u662f\u534f\u7a0b\\n";\r\n    std::cout << "   - \u53ef\u53d8\u53c2\u6570(varargs)\u51fd\u6570\u4e0d\u80fd\u662f\u534f\u7a0b\\n";\r\n}\r\n\r\n// ===================== main() =====================\r\nint main() {\r\n    std::cout << "===== \u534f\u7a0b\u57fa\u7840 - C++20 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,s.jsx)(r.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,s.jsxs)(r.ul,{children:["\n",(0,s.jsx)(r.li,{children:(0,s.jsx)(r.a,{href:"https://en.cppreference.com/w/cpp/language/coroutines",children:"cppreference: \u534f\u7a0b\u57fa\u7840 (Coroutines: co_await, co_yield, co_return)"})}),"\n"]})]})}function l(n={}){const{wrapper:r}={...(0,o.R)(),...n.components};return r?(0,s.jsx)(r,{...n,children:(0,s.jsx)(u,{...n})}):u(n)}},28453(n,r,e){e.d(r,{R:()=>a,x:()=>c});var t=e(96540);const s={},o=t.createContext(s);function a(n){const r=t.useContext(o);return t.useMemo(function(){return"function"==typeof n?n(r):{...r,...n}},[r,n])}function c(n){let r;return r=n.disableParentContext?"function"==typeof n.components?n.components(s):n.components||s:a(n.components),t.createElement(o.Provider,{value:r},n.children)}}}]);